#!/usr/bin/env bash
# gen.sh — emit a self-contained synthetic Mach program to stdout for a
# scaling signal. the program defines COUNT independent arithmetic functions
# plus a main that folds their results together, so compile time grows with
# COUNT without pulling in any external dependency.
#
# usage: tools/bench/gen.sh [count]   (count defaults to 400)
set -euo pipefail

count="${1:-400}"

cat <<'EOF'
# synthetic benchmark input — generated by tools/bench/gen.sh, do not edit by hand.
# a flat list of independent pure functions plus a main that folds them,
# sized to give the harness a compile-time scaling signal.

use std.runtime;

$main.symbol = "main";

EOF

for ((i = 0; i < count; i++)); do
    a=$((i % 97 + 1))
    b=$((i % 31 + 1))
    printf 'fun f%d(x: i64) i64 {\n' "$i"
    printf '    var y: i64 = x + %d;\n' "$a"
    printf '    y = y * %d;\n' "$b"
    printf '    y = y - (x %% %d);\n' "$a"
    printf '    if (y < 0) { y = 0 - y; }\n'
    printf '    ret y;\n'
    printf '}\n\n'
done

printf 'fun main(argc: i64, argv: **u8) i64 {\n'
printf '    var acc: i64 = 0;\n'
for ((i = 0; i < count; i++)); do
    printf '    acc = acc + f%d(acc);\n' "$i"
done
printf '    ret acc %% 256;\n'
printf '}\n'
